// ui_widgets_titlebar.cpp - Title Bar Widget Components
// ============================================================================
//
// Part of GitSmarter UI widget system. Contains the custom title bar widgets
// for window chrome (minimize/maximize/close buttons) and navigation (back button).
//
// Integration code is in platform.cpp (title_bar_init, title_bar_render, etc.)
//
// Dependencies: ui_widgets_core.cpp (Widget base, RenderContext, WidgetFlags)
//               ui_widgets_basic.cpp (Label)
