// External variables from platform.cpp
extern HWND g_main_window;
extern bool g_is_maximized;
extern IDWriteTextFormat* g_title_format;

// Forward declaration for screen navigation
extern AppScreen g_current_screen;

// Title bar layout constants (duplicated from platform.cpp since we're included before it)
namespace TitleBar {
    constexpr float BUTTON_WIDTH = 46.0f;
    constexpr float BUTTON_COUNT = 3.0f;
    constexpr float BUTTONS_TOTAL_WIDTH = BUTTON_WIDTH * BUTTON_COUNT;  // 138.0f
}

// ============================================================================
// TitleBarButtonWidget - Individual title bar button (back, min, max, close)
// ============================================================================

enum class TitleBarButtonType { Back, Minimize, Maximize, Close, Debug };

struct TitleBarButtonWidget : Widget {
    TitleBarButtonType button_type = TitleBarButtonType::Minimize;

    // Colors (transparent by default)
    uint32_t bg_normal = 0x00000000;
    uint32_t bg_hover = Theme::TITLE_BAR_BUTTON_HOVER;
    uint32_t bg_pressed = 0xFF4E4E52;
    uint32_t icon_color = Theme::TEXT_PRIMARY;
    uint32_t icon_hover_color = Theme::TEXT_PRIMARY;  // Close uses white on hover

    // Callback for custom actions (like back button)
    void (*on_click)(TitleBarButtonWidget* btn) = nullptr;

    TitleBarButtonWidget() {
        flags |= WidgetFlags::Focusable;
        preferred_width = TitleBar::BUTTON_WIDTH;
        preferred_height = Config::TITLE_BAR_HEIGHT;
        width_mode = SizeMode::Fixed;
        height_mode = SizeMode::Fixed;
    }

    void render(RenderContext& ctx) override {
        // Determine colors based on state
        uint32_t bg = bg_normal;
        uint32_t icon = icon_color;

        if (!(flags & WidgetFlags::Enabled)) {
            icon = Theme::TEXT_MUTED;
        } else if (flags & WidgetFlags::Pressed) {
            bg = bg_pressed;
            icon = icon_hover_color;
        } else if (flags & WidgetFlags::Hovered) {
            bg = bg_hover;
            icon = icon_hover_color;
        } else if (flags & WidgetFlags::Focused) {
            bg = bg_hover;
        }

        // Draw background if not transparent
        if ((bg & 0xFF000000) != 0) {
            ctx.fill_rect(D2D1::RectF(rect.x, rect.y, rect.x + rect.width, rect.y + rect.height), bg);
        }

        // Draw focus ring when focused
        if (flags & WidgetFlags::Focused) {
            D2D1_RECT_F focus_rect = D2D1::RectF(
                rect.x + 4, rect.y + 4,
                rect.x + rect.width - 4, rect.y + rect.height - 4
            );
            ctx.brush->SetColor(color_from_argb(Theme::ACCENT));
            ctx.target->DrawRectangle(focus_rect, ctx.brush, 1.0f);
        }

        // Draw icon
        ctx.brush->SetColor(color_from_argb(icon));
        float cx = rect.x + rect.width / 2.0f;
        float cy = rect.y + rect.height / 2.0f;

        switch (button_type) {
            case TitleBarButtonType::Back: {
                // Draw left chevron (<)
                float arrow_size = 5.0f;
                ctx.target->DrawLine(
                    D2D1::Point2F(cx + arrow_size * 0.3f, cy - arrow_size),
                    D2D1::Point2F(cx - arrow_size * 0.7f, cy),
                    ctx.brush, 1.2f
                );
                ctx.target->DrawLine(
                    D2D1::Point2F(cx - arrow_size * 0.7f, cy),
                    D2D1::Point2F(cx + arrow_size * 0.3f, cy + arrow_size),
                    ctx.brush, 1.2f
                );
                break;
            }
            case TitleBarButtonType::Minimize: {
                // Draw horizontal line
                ctx.target->DrawLine(
                    D2D1::Point2F(cx - 5.0f, cy),
                    D2D1::Point2F(cx + 5.0f, cy),
                    ctx.brush, 1.0f
                );
                break;
            }
            case TitleBarButtonType::Maximize: {
                if (g_is_maximized) {
                    // Draw restore icon (two overlapping rectangles)
                    D2D1_RECT_F back_rect = D2D1::RectF(cx - 3.0f, cy - 5.0f, cx + 5.0f, cy + 3.0f);
                    D2D1_RECT_F front_rect = D2D1::RectF(cx - 5.0f, cy - 3.0f, cx + 3.0f, cy + 5.0f);
                    ctx.target->DrawRectangle(back_rect, ctx.brush, 1.0f);
                    // Fill front rect background to cover back rect
                    ctx.brush->SetColor(color_from_argb(Theme::TITLE_BAR_BG));
                    ctx.target->FillRectangle(front_rect, ctx.brush);
                    ctx.brush->SetColor(color_from_argb(icon));
                    ctx.target->DrawRectangle(front_rect, ctx.brush, 1.0f);
                } else {
                    // Draw maximize icon (single rectangle)
                    D2D1_RECT_F icon_rect = D2D1::RectF(cx - 5.0f, cy - 5.0f, cx + 5.0f, cy + 5.0f);
                    ctx.target->DrawRectangle(icon_rect, ctx.brush, 1.0f);
                }
                break;
            }
            case TitleBarButtonType::Close: {
                // Draw X
                ctx.target->DrawLine(
                    D2D1::Point2F(cx - 5.0f, cy - 5.0f),
                    D2D1::Point2F(cx + 5.0f, cy + 5.0f),
                    ctx.brush, 1.0f
                );
                ctx.target->DrawLine(
                    D2D1::Point2F(cx + 5.0f, cy - 5.0f),
                    D2D1::Point2F(cx - 5.0f, cy + 5.0f),
                    ctx.brush, 1.0f
                );
                break;
            }
            case TitleBarButtonType::Debug: {
                // Draw bug/debug icon (simple "D" for debug)
                // Draw a small wrench icon
                float s = 4.0f;
                // Wrench handle (vertical line)
                ctx.target->DrawLine(
                    D2D1::Point2F(cx, cy - s),
                    D2D1::Point2F(cx, cy + s),
                    ctx.brush, 1.5f
                );
                // Wrench head (diagonal lines at top)
                ctx.target->DrawLine(
                    D2D1::Point2F(cx - s * 0.7f, cy - s * 0.5f),
                    D2D1::Point2F(cx, cy - s),
                    ctx.brush, 1.5f
                );
                ctx.target->DrawLine(
                    D2D1::Point2F(cx + s * 0.7f, cy - s * 0.5f),
                    D2D1::Point2F(cx, cy - s),
                    ctx.brush, 1.5f
                );
                break;
            }
        }
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;
        if ((vk == VK_RETURN || vk == VK_SPACE) && (flags & WidgetFlags::Enabled)) {
            execute_action();
            return true;
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        return true;  // Consume event
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        if ((flags & WidgetFlags::Hovered) && (flags & WidgetFlags::Enabled)) {
            execute_action();
        }
        return true;
    }

private:
    void execute_action() {
        // If custom callback is set, use it
        if (on_click) {
            on_click(this);
            return;
        }

        // Default window actions
        switch (button_type) {
            case TitleBarButtonType::Minimize:
                ShowWindow(g_main_window, SW_MINIMIZE);
                break;
            case TitleBarButtonType::Maximize:
                ShowWindow(g_main_window, g_is_maximized ? SW_RESTORE : SW_MAXIMIZE);
                break;
            case TitleBarButtonType::Close:
                PostMessageW(g_main_window, WM_CLOSE, 0, 0);
                break;
            case TitleBarButtonType::Back:
                // Default back action: return to welcome screen
                g_current_screen = AppScreen::Welcome;
                InvalidateRect(g_main_window, nullptr, FALSE);
                break;
        }
    }
};

// ============================================================================
// TitleBarWidget - Container for title bar buttons and title text
// ============================================================================

struct TitleBarWidget : Widget {
    // Child widgets
    TitleBarButtonWidget* btn_back = nullptr;
    Label* title_label = nullptr;
#ifdef GITSMARTER_DEBUG
    TitleBarButtonWidget* btn_debug = nullptr;
#endif
    TitleBarButtonWidget* btn_minimize = nullptr;
    TitleBarButtonWidget* btn_maximize = nullptr;
    TitleBarButtonWidget* btn_close = nullptr;

    // State
    bool show_back_button = false;
    const wchar_t* title_text = Config::APP_NAME;

    TitleBarWidget() {
        flags |= WidgetFlags::RendersOwnChildren;
        flags |= WidgetFlags::FocusGroup;  // Arrow keys navigate between buttons
        nav_direction = NavDirection::Horizontal;  // Left/Right arrows
        width_mode = SizeMode::Fill;
        height_mode = SizeMode::Fixed;
        preferred_height = Config::TITLE_BAR_HEIGHT;
    }

    void layout() override {
        // Position back button on left side
        if (btn_back) {
            btn_back->rect.x = rect.x;
            btn_back->rect.y = rect.y;
            btn_back->rect.width = TitleBar::BUTTON_WIDTH;
            btn_back->rect.height = Config::TITLE_BAR_HEIGHT;
            // Hide/show based on state
            if (show_back_button) {
                btn_back->flags |= WidgetFlags::Visible | WidgetFlags::Enabled;
            } else {
                btn_back->flags &= ~(WidgetFlags::Visible | WidgetFlags::Enabled);
            }
        }

        // Position title label
        if (title_label) {
            float title_left = rect.x + 12.0f;
            if (show_back_button && btn_back) {
                title_left = btn_back->rect.x + btn_back->rect.width + 4.0f;
            }
            title_label->rect.x = title_left;
            title_label->rect.y = rect.y;
#ifdef GITSMARTER_DEBUG
            float right_buttons_width = TitleBar::BUTTONS_TOTAL_WIDTH + TitleBar::BUTTON_WIDTH;  // +debug button
#else
            float right_buttons_width = TitleBar::BUTTONS_TOTAL_WIDTH;
#endif
            title_label->rect.width = rect.width - title_left - right_buttons_width - 12.0f;
            title_label->rect.height = Config::TITLE_BAR_HEIGHT;
        }

        // Position window control buttons on right side
#ifdef GITSMARTER_DEBUG
        float button_x = rect.x + rect.width - TitleBar::BUTTONS_TOTAL_WIDTH - TitleBar::BUTTON_WIDTH;

        // Debug button first (leftmost of right buttons)
        if (btn_debug) {
            btn_debug->rect.x = button_x;
            btn_debug->rect.y = rect.y;
            btn_debug->rect.width = TitleBar::BUTTON_WIDTH;
            btn_debug->rect.height = Config::TITLE_BAR_HEIGHT;
            button_x += TitleBar::BUTTON_WIDTH;
        }
#else
        float button_x = rect.x + rect.width - TitleBar::BUTTONS_TOTAL_WIDTH;
#endif

        if (btn_minimize) {
            btn_minimize->rect.x = button_x;
            btn_minimize->rect.y = rect.y;
            btn_minimize->rect.width = TitleBar::BUTTON_WIDTH;
            btn_minimize->rect.height = Config::TITLE_BAR_HEIGHT;
            button_x += TitleBar::BUTTON_WIDTH;
        }

        if (btn_maximize) {
            btn_maximize->rect.x = button_x;
            btn_maximize->rect.y = rect.y;
            btn_maximize->rect.width = TitleBar::BUTTON_WIDTH;
            btn_maximize->rect.height = Config::TITLE_BAR_HEIGHT;
            button_x += TitleBar::BUTTON_WIDTH;
        }

        if (btn_close) {
            btn_close->rect.x = button_x;
            btn_close->rect.y = rect.y;
            btn_close->rect.width = TitleBar::BUTTON_WIDTH;
            btn_close->rect.height = Config::TITLE_BAR_HEIGHT;
        }
    }

    void render(RenderContext& ctx) override {
        // Draw title bar background
        D2D1_RECT_F bg_rect = D2D1::RectF(rect.x, rect.y, rect.x + rect.width, rect.y + rect.height);
        ctx.fill_rect(bg_rect, Theme::TITLE_BAR_BG);

        // Render back button if visible
        if (btn_back && (btn_back->flags & WidgetFlags::Visible)) {
            btn_back->render(ctx);
        }

        // Render title
        if (title_label) {
            title_label->render(ctx);
        }

        // Render window control buttons
#ifdef GITSMARTER_DEBUG
        if (btn_debug) btn_debug->render(ctx);
#endif
        if (btn_minimize) btn_minimize->render(ctx);
        if (btn_maximize) btn_maximize->render(ctx);
        if (btn_close) btn_close->render(ctx);
    }

    // Check if a point is over the draggable caption area (not buttons)
    bool is_over_caption(float x, float y) const {
        // Must be within title bar bounds
        if (!rect.contains(x, y)) return false;

        // Not over back button
        if (show_back_button && btn_back && btn_back->rect.contains(x, y)) return false;

        // Not over window control buttons
#ifdef GITSMARTER_DEBUG
        if (btn_debug && btn_debug->rect.contains(x, y)) return false;
#endif
        if (btn_minimize && btn_minimize->rect.contains(x, y)) return false;
        if (btn_maximize && btn_maximize->rect.contains(x, y)) return false;
        if (btn_close && btn_close->rect.contains(x, y)) return false;

        // It's over the caption (title text area)
        return true;
    }

    void set_title(const wchar_t* text) {
        title_text = text;
        if (title_label) {
            title_label->text = text;
        }
    }

    void set_show_back(bool show) {
        show_back_button = show;
        layout();  // Re-layout to update positions
    }
};

// ============================================================================
// Global Title Bar Instance and Integration Functions
// ============================================================================

static TitleBarWidget* g_title_bar = nullptr;
static TitleBarButtonWidget* g_title_bar_back = nullptr;
#ifdef GITSMARTER_DEBUG
static TitleBarButtonWidget* g_title_bar_debug = nullptr;
static void debug_test_dialog_show();  // Forward declaration
#endif
static TitleBarButtonWidget* g_title_bar_minimize = nullptr;
static TitleBarButtonWidget* g_title_bar_maximize = nullptr;
static TitleBarButtonWidget* g_title_bar_close = nullptr;
static Label* g_title_bar_label = nullptr;

static void title_bar_init() {
    // Create widgets using the arena allocator
    g_title_bar = g_widget_arena.create<TitleBarWidget>();
    g_title_bar->debug_name = "TitleBar";

    // Create back button
    g_title_bar_back = g_widget_arena.create<TitleBarButtonWidget>();
    g_title_bar_back->debug_name = "TitleBar.Back";
    g_title_bar_back->button_type = TitleBarButtonType::Back;
    g_title_bar_back->flags &= ~WidgetFlags::Visible;  // Hidden by default
    g_title_bar->btn_back = g_title_bar_back;
    widget_add_child(g_title_bar, g_title_bar_back);

    // Create title label
    g_title_bar_label = g_widget_arena.create<Label>();
    g_title_bar_label->debug_name = "TitleBar.Title";
    g_title_bar_label->text = Config::APP_NAME;
    g_title_bar_label->text_format = g_title_format;
    g_title_bar_label->color = Theme::TEXT_PRIMARY;
    g_title_bar_label->text_align = DWRITE_TEXT_ALIGNMENT_LEADING;
    g_title_bar_label->para_align = DWRITE_PARAGRAPH_ALIGNMENT_CENTER;
    g_title_bar->title_label = g_title_bar_label;
    widget_add_child(g_title_bar, g_title_bar_label);

#ifdef GITSMARTER_DEBUG
    // Create debug button (opens dialog test menu)
    g_title_bar_debug = g_widget_arena.create<TitleBarButtonWidget>();
    g_title_bar_debug->debug_name = "TitleBar.Debug";
    g_title_bar_debug->button_type = TitleBarButtonType::Debug;
    g_title_bar_debug->on_click = [](TitleBarButtonWidget*) { debug_test_dialog_show(); };
    g_title_bar->btn_debug = g_title_bar_debug;
    widget_add_child(g_title_bar, g_title_bar_debug);
#endif

    // Create minimize button
    g_title_bar_minimize = g_widget_arena.create<TitleBarButtonWidget>();
    g_title_bar_minimize->debug_name = "TitleBar.Minimize";
    g_title_bar_minimize->button_type = TitleBarButtonType::Minimize;
    g_title_bar->btn_minimize = g_title_bar_minimize;
    widget_add_child(g_title_bar, g_title_bar_minimize);

    // Create maximize button
    g_title_bar_maximize = g_widget_arena.create<TitleBarButtonWidget>();
    g_title_bar_maximize->debug_name = "TitleBar.Maximize";
    g_title_bar_maximize->button_type = TitleBarButtonType::Maximize;
    g_title_bar->btn_maximize = g_title_bar_maximize;
    widget_add_child(g_title_bar, g_title_bar_maximize);

    // Create close button with special colors
    g_title_bar_close = g_widget_arena.create<TitleBarButtonWidget>();
    g_title_bar_close->debug_name = "TitleBar.Close";
    g_title_bar_close->button_type = TitleBarButtonType::Close;
    g_title_bar_close->bg_hover = Theme::TITLE_BAR_CLOSE_HOVER;
    g_title_bar_close->bg_pressed = 0xFFB71C1C;  // Darker red when pressed
    g_title_bar_close->icon_hover_color = 0xFFFFFFFF;  // White icon on hover
    g_title_bar->btn_close = g_title_bar_close;
    widget_add_child(g_title_bar, g_title_bar_close);
}

static void title_bar_render(ID2D1SolidColorBrush* brush, float window_width) {
    if (!g_title_bar) return;

    // Update title bar bounds
    g_title_bar->rect.x = 0;
    g_title_bar->rect.y = 0;
    g_title_bar->rect.width = window_width;
    g_title_bar->rect.height = Config::TITLE_BAR_HEIGHT;

    // Update back button visibility based on current screen
    g_title_bar->set_show_back(g_current_screen == AppScreen::Repository);

    // Layout children
    g_title_bar->layout();

    // Create render context and render
    RenderContext ctx;
    ctx.target = g_render_target;
    ctx.brush = brush;
    ctx.clip_depth = 0;

    g_title_bar->render(ctx);
}

// Hit test for WM_NCHITTEST - returns true if over draggable caption
static bool title_bar_is_over_caption(float x, float y) {
    if (!g_title_bar) return false;
    return g_title_bar->is_over_caption(x, y);
}

// Dispatch mouse events to title bar widgets
static Widget* title_bar_hit_test(float x, float y) {
    if (!g_title_bar || y >= Config::TITLE_BAR_HEIGHT) return nullptr;

    // Check buttons in reverse order (last rendered = on top)
    if (g_title_bar_close && g_title_bar_close->hit_test(x, y)) return g_title_bar_close;
    if (g_title_bar_maximize && g_title_bar_maximize->hit_test(x, y)) return g_title_bar_maximize;
    if (g_title_bar_minimize && g_title_bar_minimize->hit_test(x, y)) return g_title_bar_minimize;
#ifdef GITSMARTER_DEBUG
    if (g_title_bar_debug && g_title_bar_debug->hit_test(x, y)) return g_title_bar_debug;
#endif
    if (g_title_bar->show_back_button && g_title_bar_back && g_title_bar_back->hit_test(x, y)) return g_title_bar_back;

    return nullptr;
}

// Track currently hovered title bar button
static Widget* g_title_bar_hovered = nullptr;

// Dispatch mouse move to title bar widgets - returns true if state changed
static bool title_bar_dispatch_mouse_move(float x, float y) {
    Widget* hit = title_bar_hit_test(x, y);
    bool changed = false;

    // Handle leave for previous hover
    if (g_title_bar_hovered && g_title_bar_hovered != hit) {
        g_title_bar_hovered->flags &= ~WidgetFlags::Hovered;
        g_title_bar_hovered->on_mouse_leave();
        changed = true;
    }

    // Handle enter for new hover
    if (hit && hit != g_title_bar_hovered) {
        hit->flags |= WidgetFlags::Hovered;
        hit->on_mouse_enter();
        changed = true;
    }

    g_title_bar_hovered = hit;
    return changed;
}

// Dispatch mouse down to title bar widgets - returns true if handled
static bool title_bar_dispatch_mouse_down(float x, float y, int button) {
    Widget* hit = title_bar_hit_test(x, y);
    if (hit) {
        hit->flags |= WidgetFlags::Pressed;
        hit->on_mouse_down(x, y, button);
        return true;
    }
    return false;
}

// Dispatch mouse up to title bar widgets - returns true if handled
static bool title_bar_dispatch_mouse_up(float x, float y, int button) {
    // Get the widget that was pressed
    Widget* hit = title_bar_hit_test(x, y);

    // Clear pressed state from all buttons
    if (g_title_bar_back) g_title_bar_back->flags &= ~WidgetFlags::Pressed;
#ifdef GITSMARTER_DEBUG
    if (g_title_bar_debug) g_title_bar_debug->flags &= ~WidgetFlags::Pressed;
#endif
    if (g_title_bar_minimize) g_title_bar_minimize->flags &= ~WidgetFlags::Pressed;
    if (g_title_bar_maximize) g_title_bar_maximize->flags &= ~WidgetFlags::Pressed;
    if (g_title_bar_close) g_title_bar_close->flags &= ~WidgetFlags::Pressed;

    // If we're still over a button, dispatch the mouse up
    if (hit) {
        // Ensure Hovered flag is set - hit_test confirmed mouse is over this widget.
        // This fixes a bug where hover was never updated while a dialog was active
        // (g_event_dispatcher consumed mouse_move, bypassing title_bar_dispatch_mouse_move).
        hit->flags |= WidgetFlags::Hovered;
        g_title_bar_hovered = hit;
        hit->on_mouse_up(x, y, button);
        return true;
    }

    return false;
}

// Clear all title bar hover states
static void title_bar_clear_hover() {
    if (g_title_bar_hovered) {
        g_title_bar_hovered->flags &= ~WidgetFlags::Hovered;
        g_title_bar_hovered->on_mouse_leave();
        g_title_bar_hovered = nullptr;
    }
}
